{
  "name": "SimPro - Sistem Pengajuan Bahan Pelatihan",
  "description": "A streamlined platform for instructors to submit material requests and for organizers to manage procurement workflows efficiently."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum RequestStatus {
  DRAFT = 'Draft',
  PENDING = 'Menunggu Verifikasi',
  REVISION = 'Perlu Revisi',
  APPROVED = 'Disetujui Penyelenggara',
  FORWARDED = 'Diteruskan ke PPK',
  COMPLETED = 'Selesai Pengadaan'
}

export enum UserRole {
  INSTRUCTOR = 'Instruktur',
  ORGANIZER = 'Penyelenggara'
}

export interface MaterialItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  spec: string;
}

export interface MaterialRequest {
  id: string;
  instructorName: string;
  trainingTitle: string;
  dateSubmitted: string;
  items: MaterialItem[];
  status: RequestStatus;
  notes?: string;
  organizerComment?: string;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const suggestMaterials = async (trainingTitle: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Berikan daftar saran bahan pelatihan yang dibutuhkan untuk topik: "${trainingTitle}".`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING, description: "Nama barang" },
              quantity: { type: Type.NUMBER, description: "Jumlah standar" },
              unit: { type: Type.STRING, description: "Satuan (misal: Rim, Pack, Buah)" },
              spec: { type: Type.STRING, description: "Spesifikasi singkat" }
            },
            required: ["name", "quantity", "unit", "spec"]
          }
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Suggestion Error:", error);
    return [];
  }
};

import React from 'react';
