export default DashboardHeader;

import React, { useState } from 'react';
import { MaterialRequest, MaterialItem, RequestStatus } from '../types';
import { suggestMaterials } from '../services/geminiService';

interface InstructorViewProps {
  requests: MaterialRequest[];
  onSubmit: (req: Partial<MaterialRequest>) => void;
}

const InstructorView: React.FC<InstructorViewProps> = ({ requests, onSubmit }) => {
  const [showForm, setShowForm] = useState(false);
  const [trainingTitle, setTrainingTitle] = useState('');
  const [items, setItems] = useState<MaterialItem[]>([]);
  const [loadingAI, setLoadingAI] = useState(false);

  const handleAISuggest = async () => {
    if (!trainingTitle) return alert("Masukkan judul pelatihan dulu, bro!");
    setLoadingAI(true);
    const suggested = await suggestMaterials(trainingTitle);
    const mapped: MaterialItem[] = suggested.map((s: any, idx: number) => ({
      id: Math.random().toString(36).substr(2, 9),
      name: s.name,
      quantity: s.quantity,
      unit: s.unit,
      spec: s.spec
    }));
    setItems(mapped);
    setLoadingAI(false);
  };

  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), name: '', quantity: 1, unit: 'Buah', spec: '' }]);
  };

  const updateItem = (id: string, field: keyof MaterialItem, value: any) => {
    setItems(items.map(it => it.id === id ? { ...it, [field]: value } : it));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (items.length === 0) return alert("Daftar barang tidak boleh kosong!");
    onSubmit({
      trainingTitle,
      items,
      instructorName: "Instruktur Demo",
      status: RequestStatus.PENDING,
      dateSubmitted: new Date().toISOString()
    });
    setTrainingTitle('');
    setItems([]);
    setShowForm(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Dashboard Instruktur</h2>
          <p className="text-slate-500">Ajukan kebutuhan bahan untuk kelancaran pelatihan Anda.</p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-medium transition-colors flex items-center gap-2 shadow-sm"
        >
          {showForm ? 'Batal' : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
              </svg>
              Buat Pengajuan
            </>
          )}
        </button>
      </div>

      {showForm && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden transition-all animate-in fade-in slide-in-from-top-4 duration-300">
          <div className="p-6">
            <h3 className="text-lg font-semibold mb-4">Form Pengajuan Baru</h3>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Judul Pelatihan</label>
                <div className="flex gap-2">
                  <input
                    type="text"
                    required
                    value={trainingTitle}
                    onChange={(e) => setTrainingTitle(e.target.value)}
                    placeholder="Contoh: Pelatihan Digital Marketing Tingkat Lanjut"
                    className="flex-1 rounded-lg border-slate-300 focus:ring-blue-500 focus:border-blue-500 text-sm shadow-sm"
                  />
                  <button
                    type="button"
                    onClick={handleAISuggest}
                    disabled={loadingAI}
                    className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-lg text-sm font-semibold hover:bg-indigo-100 transition-colors disabled:opacity-50 flex items-center gap-2"
                  >
                    {loadingAI ? 'Berpikir...' : (
                      <>
                        <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71L12 2z"/></svg>
                        Bantu AI
                      </>
                    )}
                  </button>
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex justify-between items-center">
                  <h4 className="text-sm font-semibold text-slate-700">Daftar Barang</h4>
                  <button type="button" onClick={addItem} className="text-blue-600 text-xs font-bold hover:underline">+ Tambah Manual</button>
                </div>
                {items.map((item, idx) => (
                  <div key={item.id} className="grid grid-cols-12 gap-3 p-3 bg-slate-50 rounded-lg border border-slate-100 items-center">
                    <div className="col-span-1 text-xs font-bold text-slate-400">{idx + 1}</div>
                    <div className="col-span-5">
                      <input
                        placeholder="Nama Barang"
                        className="w-full text-xs rounded border-slate-200"
                        value={item.name}
                        onChange={(e) => updateItem(item.id, 'name', e.target.value)}
                      />
                    </div>
                    <div className="col-span-2">
                      <input
                        type="number"
                        placeholder="Qty"
                        className="w-full text-xs rounded border-slate-200"
                        value={item.quantity}
                        onChange={(e) => updateItem(item.id, 'quantity', parseInt(e.target.value))}
                      />
                    </div>
                    <div className="col-span-2">
                      <input
                        placeholder="Satuan"
                        className="w-full text-xs rounded border-slate-200"
                        value={item.unit}
                        onChange={(e) => updateItem(item.id, 'unit', e.target.value)}
                      />
                    </div>
                    <div className="col-span-2">
                      <button 
                        type="button" 
                        onClick={() => setItems(items.filter(i => i.id !== item.id))}
                        className="text-red-400 hover:text-red-600"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                      </button>
                    </div>
                    <div className="col-span-12 mt-1">
                      <input
                        placeholder="Spesifikasi (Merk, Warna, dsb)"
                        className="w-full text-xs rounded border-slate-200 italic"
                        value={item.spec}
                        onChange={(e) => updateItem(item.id, 'spec', e.target.value)}
                      />
                    </div>
                  </div>
                ))}
              </div>

              <div className="pt-4 border-t border-slate-100 flex justify-end">
                <button
                  type="submit"
                  className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-blue-700 shadow-md"
                >
                  Kirim Pengajuan
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="min-w-full divide-y divide-slate-200">
          <thead className="bg-slate-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Topik Pelatihan</th>
              <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Tanggal</th>
              <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider">Status</th>
              <th className="px-6 py-3 text-right text-xs font-bold text-slate-500 uppercase tracking-wider">Aksi</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-slate-200">
            {requests.length === 0 ? (
              <tr>
                <td colSpan={4} className="px-6 py-10 text-center text-slate-400">Belum ada pengajuan.</td>
              </tr>
            ) : requests.map((req) => (
              <tr key={req.id} className="hover:bg-slate-50">
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="text-sm font-semibold text-slate-900">{req.trainingTitle}</div>
                  <div className="text-xs text-slate-500">{req.items.length} item barang</div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500">
                  {new Date(req.dateSubmitted).toLocaleDateString('id-ID')}
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className={`px-2 py-1 text-xs font-bold rounded-full ${
                    req.status === RequestStatus.APPROVED ? 'bg-green-100 text-green-700' :
                    req.status === RequestStatus.PENDING ? 'bg-amber-100 text-amber-700' :
                    req.status === RequestStatus.REVISION ? 'bg-red-100 text-red-700' :
                    'bg-slate-100 text-slate-700'
                  }`}>
                    {req.status}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                  <button className="text-blue-600 hover:text-blue-900">Detail</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default InstructorView;

import React from 'react';
import { MaterialRequest, RequestStatus } from '../types';

interface OrganizerViewProps {
  requests: MaterialRequest[];
  onAction: (id: string, status: RequestStatus, comment?: string) => void;
}

const OrganizerView: React.FC<OrganizerViewProps> = ({ requests, onAction }) => {
  const pendingRequests = requests.filter(r => r.status === RequestStatus.PENDING);
  const otherRequests = requests.filter(r => r.status !== RequestStatus.PENDING);

  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-2xl font-bold text-slate-900">Kotak Masuk Penyelenggara</h2>
        <p className="text-slate-500">Verifikasi dan teruskan pengajuan bahan dari instruktur.</p>
      </div>

      <div className="space-y-4">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest">Antrian Baru ({pendingRequests.length})</h3>
        {pendingRequests.length === 0 ? (
          <div className="bg-slate-100 border-2 border-dashed border-slate-200 rounded-xl p-8 text-center text-slate-400">
            Tidak ada pengajuan yang butuh review saat ini. Kerja bagus!
          </div>
        ) : (
          <div className="grid gap-6">
            {pendingRequests.map(req => (
              <div key={req.id} className="bg-white border border-slate-200 rounded-xl shadow-sm hover:shadow-md transition-shadow">
                <div className="p-6">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h4 className="text-lg font-bold text-slate-900">{req.trainingTitle}</h4>
                      <p className="text-sm text-slate-500">Dari: <span className="font-semibold text-blue-600">{req.instructorName}</span> • {new Date(req.dateSubmitted).toLocaleDateString('id-ID')}</p>
                    </div>
                    <span className="px-3 py-1 bg-amber-50 text-amber-700 text-xs font-bold rounded-full ring-1 ring-amber-200">Menunggu</span>
                  </div>

                  <div className="bg-slate-50 rounded-lg p-4 mb-6">
                    <h5 className="text-xs font-bold text-slate-500 uppercase mb-3">Detail Barang:</h5>
                    <ul className="space-y-2">
                      {req.items.map((item, i) => (
                        <li key={i} className="text-sm text-slate-700 flex justify-between">
                          <span>{item.name} <span className="text-xs text-slate-400 italic">({item.spec})</span></span>
                          <span className="font-bold">{item.quantity} {item.unit}</span>
                        </li>
                      ))}
                    </ul>
                  </div>

                  <div className="flex flex-col sm:flex-row gap-3 pt-4 border-t border-slate-100">
                    <button
                      onClick={() => onAction(req.id, RequestStatus.APPROVED)}
                      className="flex-1 bg-green-600 hover:bg-green-700 text-white font-bold py-2 rounded-lg text-sm transition-colors shadow-sm"
                    >
                      Setujui & Teruskan
                    </button>
                    <button
                      onClick={() => {
                        const msg = prompt("Alasan revisi:");
                        if (msg) onAction(req.id, RequestStatus.REVISION, msg);
                      }}
                      className="flex-1 bg-white border border-red-200 text-red-600 hover:bg-red-50 font-bold py-2 rounded-lg text-sm transition-colors"
                    >
                      Minta Revisi
                    </button>
                    <button
                      className="px-4 py-2 border border-slate-200 text-slate-600 hover:bg-slate-50 rounded-lg text-sm font-semibold"
                    >
                      Cetak PDF
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="pt-6 border-t border-slate-200">
        <h3 className="text-sm font-bold text-slate-500 uppercase tracking-widest mb-4">Riwayat Pengajuan</h3>
        <div className="bg-white border border-slate-200 rounded-xl overflow-hidden shadow-sm">
          <table className="min-w-full divide-y divide-slate-200">
            <thead className="bg-slate-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Pelatihan</th>
                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Instruktur</th>
                <th className="px-6 py-3 text-left text-xs font-bold text-slate-500 uppercase">Status Akhir</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-200">
              {otherRequests.map(req => (
                <tr key={req.id}>
                  <td className="px-6 py-4 whitespace-nowrap text-sm font-semibold">{req.trainingTitle}</td>
                  <td className="px-6 py-4 whitespace-nowrap text-sm">{req.instructorName}</td>
                  <td className="px-6 py-4 whitespace-nowrap">
                    <span className={`px-2 py-0.5 rounded-full text-xs font-bold ${
                      req.status === RequestStatus.APPROVED ? 'bg-green-100 text-green-700' :
                      req.status === RequestStatus.REVISION ? 'bg-red-100 text-red-700' :
                      'bg-slate-100 text-slate-500'
                    }`}>
                      {req.status}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default OrganizerView;

import React, { useState, useEffect } from 'react';
import { MaterialRequest, UserRole, RequestStatus } from './types';
import DashboardHeader from './components/DashboardHeader';
import InstructorView from './components/InstructorView';
import OrganizerView from './components/OrganizerView';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.INSTRUCTOR);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);

  // Load mock data on mount
  useEffect(() => {
    const saved = localStorage.getItem('simpro_requests');
    if (saved) {
      setRequests(JSON.parse(saved));
    } else {
      // Seed initial mock
      const mock: MaterialRequest[] = [
        {
          id: '1',
          instructorName: 'Ahmad S.',
          trainingTitle: 'Workshop Dasar Robotika',
          dateSubmitted: new Date(Date.now() - 86400000).toISOString(),
          items: [
            { id: 'i1', name: 'Arduino Uno', quantity: 20, unit: 'Buah', spec: 'SMD Edition' },
            { id: 'i2', name: 'Kabel Jumper', quantity: 5, unit: 'Bundle', spec: 'Male to Female' }
          ],
          status: RequestStatus.APPROVED
        }
      ];
      setRequests(mock);
      localStorage.setItem('simpro_requests', JSON.stringify(mock));
    }
  }, []);

  const saveRequests = (newReqs: MaterialRequest[]) => {
    setRequests(newReqs);
    localStorage.setItem('simpro_requests', JSON.stringify(newReqs));
  };

  const handleInstructorSubmit = (req: Partial<MaterialRequest>) => {
    const newReq: MaterialRequest = {
      ...req,
      id: Math.random().toString(36).substr(2, 9),
    } as MaterialRequest;
    saveRequests([newReq, ...requests]);
  };

  const handleOrganizerAction = (id: string, status: RequestStatus, comment?: string) => {
    const updated = requests.map(r => 
      r.id === id ? { ...r, status, organizerComment: comment || r.organizerComment } : r
    );
    saveRequests(updated);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <DashboardHeader activeRole={role} setRole={setRole} />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="max-w-4xl mx-auto">
          {role === UserRole.INSTRUCTOR ? (
            <InstructorView 
              requests={requests.filter(r => r.instructorName === "Instruktur Demo" || r.instructorName === "Ahmad S.")}
              onSubmit={handleInstructorSubmit}
            />
          ) : (
            <OrganizerView 
              requests={requests}
              onAction={handleOrganizerAction}
            />
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-6 mt-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex justify-between items-center text-slate-400 text-sm">
          <p>© 2024 SimPro - Training Logistic System</p>
          <div className="flex gap-4">
            <span className="flex items-center gap-1">
              <span className="w-2 h-2 rounded-full bg-green-500"></span>
              Sistem Aktif
            </span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

export enum RequestStatus {
  DRAFT = 'Draft',
  PENDING = 'Menunggu Verifikasi',
  REVISION = 'Perlu Revisi',
  APPROVED = 'Disetujui Penyelenggara',
  FORWARDED = 'Diteruskan ke PPK',
  COMPLETED = 'Selesai Pengadaan'
}

export enum UserRole {
  INSTRUCTOR = 'Instruktur',
  ORGANIZER = 'Penyelenggara'
}

export enum VocationalCategory {
  TIK = 'TIK',
  PARIWISATA = 'Pariwisata',
  BAHASA = 'Bahasa',
  GARMEN = 'Garmen',
  ELEKTRONIKA = 'Elektronika',
  LISTRIK = 'Listrik',
  REFRIGERASI = 'Refrigerasi',
  MANUFAKTUR = 'Manufaktur',
  LAS = 'Las',
  OTOMOTIF = 'Otomotif',
  BANGUNAN = 'Bangunan',
  PROCESSING = 'Processing'
}

export interface MaterialItem {
  id: string;
  name: string;
  quantity: number;
  unit: string;
  spec: string;
}

export interface MaterialRequest {
  id: string;
  instructorName: string;
  trainingTitle: string;
  vocation: VocationalCategory;
  dateSubmitted: string;
  items: MaterialItem[];
  status: RequestStatus;
  notes?: string;
  organizerComment?: string;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const suggestMaterials = async (trainingTitle: string, vocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Berikan daftar saran bahan pelatihan yang dibutuhkan untuk topik: "${trainingTitle}" dalam bidang kejuruan: "${vocation}". Berikan item yang sangat relevan dengan praktik kejuruan tersebut.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING, description: "Nama barang" },
              quantity: { type: Type.NUMBER, description: "Jumlah standar" },
              unit: { type: Type.STRING, description: "Satuan (misal: Rim, Pack, Buah)" },
              spec: { type: Type.STRING, description: "Spesifikasi singkat" }
            },
            required: ["name", "quantity", "unit", "spec"]
          }
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Suggestion Error:", error);
    return [];
  }
};

