  const handleOrganizerAction = (id: string, status: RequestStatus, comment?: string) => {
    const updated = requests.map(r => 
      r.id === id ? { ...r, status, organizerComment: comment || r.organizerComment } : r
    );
    saveRequests(updated);
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50/50">
      <DashboardHeader activeRole={role} setRole={setRole} />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="max-w-5xl mx-auto">
          {role === UserRole.INSTRUCTOR ? (
            <InstructorView 
              requests={requests.filter(r => r.instructorName === "Instruktur Demo")}
              onSubmit={handleInstructorSubmit}
            />
          ) : (
            <OrganizerView 
              requests={requests}
              onAction={handleOrganizerAction}
            />
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-8 mt-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col sm:flex-row justify-between items-center gap-4 text-slate-400 text-xs">
          <div className="flex items-center gap-4">
            <h1 className="text-sm font-black text-slate-300 tracking-tighter uppercase">SimPro</h1>
            <p>© 2024 - Sistem Pengadaan Bahan Pelatihan Terpadu</p>
          </div>
          <div className="flex gap-6 font-bold uppercase tracking-widest text-[10px]">
            <span className="flex items-center gap-2 text-slate-300">
              <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></span>
              Sistem Aktif
            </span>
            <span className="hover:text-blue-500 cursor-pointer transition-colors text-slate-300">Bantuan</span>
            <span className="hover:text-blue-500 cursor-pointer transition-colors text-slate-300">Panduan</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

