                >
                  Kirim Sekarang
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-100">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-6 py-5 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Kelas & Program</th>
                <th className="px-6 py-5 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Lampiran</th>
                <th className="px-6 py-5 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Tanggal</th>
                <th className="px-6 py-5 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                <th className="px-6 py-5 text-right text-[10px] font-black text-slate-400 uppercase tracking-widest">Aksi</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-100">
              {requests.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-16 text-center">
                    <div className="text-slate-300 italic flex flex-col items-center gap-2">
                      <svg className="w-12 h-12 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M9 13h6m-3-3v6m-9 1V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z"/></svg>
                      Belum ada pengajuan terdaftar.
                    </div>
                  </td>
                </tr>
              ) : requests.map((req) => (
                <tr key={req.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-5">
                    <div className="text-sm font-black text-slate-800 mb-1.5">{req.trainingTitle}</div>
                    <div className="flex flex-col gap-1">
                      <div className="flex items-center gap-2">
                        <span className={`text-[9px] px-2 py-0.5 rounded-full font-black uppercase border shadow-sm ${VOCATION_COLORS[req.vocation] || 'bg-slate-100'}`}>
                          {req.vocation}
                        </span>
                      </div>
                      <span className="text-[11px] font-bold text-slate-500">{req.proglat}</span>
                    </div>
                  </td>
                  <td className="px-6 py-5">
                    {req.attachmentName ? (
                       <div className="flex items-center gap-2 text-[11px] font-bold text-blue-600 bg-blue-50 px-2.5 py-1.5 rounded-lg w-fit border border-blue-100">
                         <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                         {req.attachmentName}
                       </div>
                    ) : (
                      <span className="text-[10px] text-slate-300 italic font-medium">No File</span>
                    )}
                  </td>
                  <td className="px-6 py-5 whitespace-nowrap">
                    <div className="text-xs font-bold text-slate-600">{new Date(req.dateSubmitted).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}</div>
                    <div className="text-[9px] text-slate-400 font-medium uppercase">{new Date(req.dateSubmitted).getFullYear()}</div>
                  </td>
                  <td className="px-6 py-5">
                    <span className={`px-2.5 py-1 text-[9px] font-black rounded-full uppercase tracking-wider border shadow-sm ${
                      req.status === RequestStatus.APPROVED ? 'bg-green-50 text-green-700 border-green-200' :
                      req.status === RequestStatus.PENDING ? 'bg-amber-50 text-amber-700 border-amber-200' :
                      req.status === RequestStatus.REVISION ? 'bg-red-50 text-red-700 border-red-200' :
                      'bg-slate-50 text-slate-700 border-slate-200'
                    }`}>
                      {req.status}
                    </span>
                  </td>
                  <td className="px-6 py-5 text-right">
                    <button className="text-[11px] font-black uppercase text-blue-600 hover:text-white bg-blue-50 hover:bg-blue-600 px-4 py-2 rounded-xl transition-all tracking-widest border border-blue-100">
                      Detail
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

