import OrganizerView from './components/OrganizerView';

const App: React.FC = () => {
  const [role, setRole] = useState<UserRole>(UserRole.INSTRUCTOR);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);

  // Load mock data on mount
  useEffect(() => {
    const saved = localStorage.getItem('simpro_requests');
    if (saved) {
      setRequests(JSON.parse(saved));
    } else {
      // Seed initial mock with new structure including Proglat
      const mock: MaterialRequest[] = [
        {
          id: 'tik-1',
          instructorName: 'Instruktur Demo',
          trainingTitle: 'Workshop Modern Web',
          vocation: VocationalCategory.TIK,
          proglat: PROGLAT_MAPPING[VocationalCategory.TIK][0],
          dateSubmitted: new Date(Date.now() - 1800000).toISOString(),
          items: [],
          attachmentName: 'daftar_bahan_web.xlsx',
          status: RequestStatus.PENDING
        },
        {
          id: 'las-1',
          instructorName: 'Instruktur Demo',
          trainingTitle: 'Sertifikasi Welder 2024',
          vocation: VocationalCategory.LAS,
          proglat: 'Plate Welder SMAW 3G',
          dateSubmitted: new Date(Date.now() - 5400000).toISOString(),
          items: [],
          attachmentName: 'kebutuhan_elektroda.pdf',
          status: RequestStatus.PENDING
        },
        {
          id: 'oto-1',
          instructorName: 'Instruktur Demo',
          trainingTitle: 'Pelatihan Mekanik Junior',
          vocation: VocationalCategory.OTOMOTIF,
          proglat: 'Servis Sepeda Motor Injeksi',
          dateSubmitted: new Date(Date.now() - 86400000).toISOString(),
          items: [],
          attachmentName: 'sparepart_praktik.xlsx',
          status: RequestStatus.APPROVED
        },
        {
          id: 'bag-1',
          instructorName: 'Instruktur Demo',
          trainingTitle: 'Drafting Dasar',
          vocation: VocationalCategory.BANGUNAN,
          proglat: 'Drafter CAD',
          dateSubmitted: new Date(Date.now() - 172800000).toISOString(),
          items: [],
          attachmentName: 'peralatan_gambar.pdf',
          status: RequestStatus.REVISION,
          organizerComment: "Spesifikasi software mohon diperjelas."
        },
        {
          id: 'ref-1',
          instructorName: 'Instruktur Demo',
          trainingTitle: 'Teknisi AC Rumah Tangga',
          vocation: VocationalCategory.REFRIGERASI,
          proglat: 'Teknisi AC Split',
          dateSubmitted: new Date(Date.now() - 259200000).toISOString(),
          items: [],
          attachmentName: 'refrigerant_tools.xlsx',
          status: RequestStatus.PENDING
        }
      ];
      setRequests(mock);
      localStorage.setItem('simpro_requests', JSON.stringify(mock));
    }
  }, []);

  const saveRequests = (newReqs: MaterialRequest[]) => {
    setRequests(newReqs);
    localStorage.setItem('simpro_requests', JSON.stringify(newReqs));
  };

  const handleInstructorSubmit = (req: Partial<MaterialRequest>) => {
    const newReq: MaterialRequest = {
      ...req,
      id: Math.random().toString(36).substr(2, 9),
    } as MaterialRequest;
    saveRequests([newReq, ...requests]);
  };

  const handleOrganizerAction = (id: string, status: RequestStatus, comment?: string, signedDoc?: string) => {
    const updated = requests.map(r => 
      r.id === id ? { 
        ...r, 
        status, 
        organizerComment: comment || r.organizerComment,
        signedDocumentName: signedDoc || r.signedDocumentName 
      } : r
    );
    saveRequests(updated);
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50/50 selection:bg-blue-100 selection:text-blue-900">
      <DashboardHeader activeRole={role} setRole={setRole} />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="max-w-5xl mx-auto">
          {role === UserRole.INSTRUCTOR ? (
            <InstructorView 
              requests={requests.filter(r => r.instructorName === "Instruktur Demo")}
              onSubmit={handleInstructorSubmit}
            />
          ) : (
            <OrganizerView 
              requests={requests}
              onAction={handleOrganizerAction}
            />
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-10 mt-16">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col sm:flex-row justify-between items-center gap-6 text-slate-400 text-[11px] font-bold uppercase tracking-widest">
          <div className="flex items-center gap-6">
            <h1 className="text-base font-black text-slate-300 tracking-tighter">SIMPRO.ID</h1>
            <p className="border-l border-slate-200 pl-6">© 2024 Logistic Training System</p>
          </div>
          <div className="flex gap-8">
            <span className="flex items-center gap-2 text-slate-400">
              <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]"></span>
              Server Online
            </span>
            <span className="hover:text-blue-500 cursor-pointer transition-colors">Documentation</span>
            <span className="hover:text-blue-500 cursor-pointer transition-colors">Contact Support</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { MaterialRequest, RequestStatus, VocationalCategory, VOCATION_COLORS, PROGLAT_MAPPING } from '../types';

interface InstructorViewProps {
  requests: MaterialRequest[];
  onSubmit: (req: Partial<MaterialRequest>) => void;
}

const InstructorView: React.FC<InstructorViewProps> = ({ requests, onSubmit }) => {
  const [showForm, setShowForm] = useState(false);
  const [trainingTitle, setTrainingTitle] = useState('');
  const [vocation, setVocation] = useState<VocationalCategory>(VocationalCategory.TIK);
  const [proglat, setProglat] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Revision Modal State
  const [selectedRequestForNote, setSelectedRequestForNote] = useState<MaterialRequest | null>(null);
  const [isNoteModalOpen, setIsNoteModalOpen] = useState(false);

  // Sync proglat when vocation changes
  useEffect(() => {
    const programs = PROGLAT_MAPPING[vocation] || [];
    setProglat(programs[0] || '');
  }, [vocation]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setFile(e.dataTransfer.files[0]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) return alert("Silakan upload dokumen pengajuan (Excel/PDF) terlebih dahulu!");

    onSubmit({
      trainingTitle,
      vocation,
      proglat,
      items: [],
      attachmentName: file.name,
      instructorName: "Instruktur Demo",
      status: RequestStatus.PENDING,
      dateSubmitted: new Date().toISOString()
    });

    setTrainingTitle('');
    setFile(null);
    setShowForm(false);
  };

  const openNoteModal = (req: MaterialRequest) => {
    setSelectedRequestForNote(req);
    setIsNoteModalOpen(true);
  };

  return (
    <div className="space-y-6">
      {/* Note Modal for Revision */}
      {isNoteModalOpen && selectedRequestForNote && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8">
              <div className="flex justify-between items-start mb-6">
                <div className="bg-red-100 p-3 rounded-2xl">
                  <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                  </svg>
                </div>
                <button onClick={() => setIsNoteModalOpen(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              <h3 className="text-2xl font-black text-slate-900 mb-2">Pesan Perbaikan</h3>
              <p className="text-slate-500 text-sm mb-6 leading-relaxed italic">
                Penyelenggara memberikan catatan berikut untuk pengajuan <b>"{selectedRequestForNote.trainingTitle}"</b>:
              </p>

              <div className="bg-slate-50 border-2 border-red-50 rounded-2xl p-6 mb-8">
                <p className="text-slate-700 font-bold leading-relaxed whitespace-pre-wrap">
                  {selectedRequestForNote.organizerComment || "Tidak ada catatan spesifik."}
                </p>
              </div>

              <div className="flex justify-end">
                <button 
                  onClick={() => setIsNoteModalOpen(false)}
                  className="bg-slate-900 text-white px-8 py-3 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl shadow-slate-200 transition-all active:scale-95"
                >
                  Saya Mengerti
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Dashboard Instruktur</h2>
          <p className="text-slate-500 text-sm">Kelola pengajuan bahan pelatihan Anda.</p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 shadow-lg shadow-blue-100 active:scale-95"
        >
          {showForm ? 'Tutup Form' : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
              </svg>
              Buat Pengajuan
            </>
          )}
        </button>
      </div>

      {showForm && (
        <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-200">
          <div className="p-8">
            <div className="flex items-center gap-3 mb-8 pb-4 border-b border-slate-100">
              <div className="bg-blue-100 p-2.5 rounded-xl">
                <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Form Pengajuan Bahan</h3>
