                    >
                      {Object.values(VocationalCategory).map((v) => (
                        <option key={v} value={v}>{v}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Program Pelatihan (Proglat)</label>
                    <select
                      value={proglat}
                      onChange={(e) => setProglat(e.target.value)}
                      className="w-full bg-slate-50 border-slate-200 rounded-xl py-3 px-4 text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-100 focus:border-blue-400 transition-all cursor-pointer"
                    >
                      {(PROGLAT_MAPPING[vocation] || []).map((p) => (
                        <option key={p} value={p}>{p}</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="space-y-6">
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Judul Pelatihan</label>
                    <input
                      type="text"
                      required
                      value={trainingTitle}
                      onChange={(e) => setTrainingTitle(e.target.value)}
