                    >
                      <input
                        type="file"
                        accept=".xlsx,.xls,.pdf"
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                      />
                      <div className="flex flex-col items-center gap-2">
                        {file ? (
                          <>
                            <div className="bg-green-100 p-2 rounded-lg mb-1">
                              <svg className="w-6 h-6 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                              </svg>
                            </div>
                            <span className="text-sm font-bold text-slate-700 truncate max-w-full px-4">{file.name}</span>
                            <span className="text-[10px] text-slate-400 uppercase font-black">Klik untuk ganti file</span>
                          </>
                        ) : (
                          <>
                            <div className="bg-blue-100 p-2 rounded-lg mb-1">
                              <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                              </svg>
                            </div>
                            <span className="text-sm font-bold text-slate-600">Drag & Drop file atau klik untuk upload</span>
                            <span className="text-[10px] text-slate-400 font-bold">Dukungan: .xlsx, .xls, .pdf</span>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                </div>
              </div>

              <div className="pt-6 border-t border-slate-100 flex justify-end items-center gap-4">
                <span className="text-xs text-slate-400 font-medium italic">*Pastikan format dokumen sesuai template standar</span>
                <button
                  type="submit"
                  className="bg-blue-600 text-white px-10 py-3.5 rounded-xl font-black uppercase tracking-widest hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  Kirim Sekarang
                </button>
              </div>
            </form>
          </div>
        </div>
