import React, { useState, useEffect } from 'react';
import { MaterialRequest, RequestStatus, VocationalCategory, VOCATION_COLORS, PROGLAT_MAPPING, User } from '../types';

interface InstructorViewProps {
  user: User;
  requests: MaterialRequest[];
  onSubmit: (req: Partial<MaterialRequest>) => void;
}

const InstructorView: React.FC<InstructorViewProps> = ({ user, requests, onSubmit }) => {
  const [showForm, setShowForm] = useState(false);
  const [trainingTitle, setTrainingTitle] = useState('');
  const [vocation, setVocation] = useState<VocationalCategory>(user.vocation || VocationalCategory.TIK);
  const [proglat, setProglat] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Revision Modal State
  const [selectedRequestForNote, setSelectedRequestForNote] = useState<MaterialRequest | null>(null);
  const [isNoteModalOpen, setIsNoteModalOpen] = useState(false);

  // Sync proglat when vocation changes
  useEffect(() => {
    const programs = PROGLAT_MAPPING[vocation] || [];
    setProglat(programs[0] || '');
  }, [vocation]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setFile(e.dataTransfer.files[0]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) return alert("Silakan upload dokumen pengajuan (Excel/PDF) terlebih dahulu!");

    onSubmit({
      trainingTitle,
      vocation,
      proglat,
      items: [],
      attachmentName: file.name,
      instructorName: user.username,
      status: RequestStatus.PENDING,
      dateSubmitted: new Date().toISOString()
    });

    setTrainingTitle('');
    setFile(null);
    setShowForm(false);
  };

  const openNoteModal = (req: MaterialRequest) => {
    setSelectedRequestForNote(req);
    setIsNoteModalOpen(true);
  };

  const handlePerbaiki = () => {
    if (selectedRequestForNote) {
      setTrainingTitle(selectedRequestForNote.trainingTitle);
      setVocation(selectedRequestForNote.vocation);
      setProglat(selectedRequestForNote.proglat);
      setShowForm(true);
      setIsNoteModalOpen(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Note Modal for Revision */}
      {isNoteModalOpen && selectedRequestForNote && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8">
              <div className="flex justify-between items-start mb-6">
                <div className="bg-red-100 p-3 rounded-2xl">
                  <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                  </svg>
                </div>
                <button onClick={() => setIsNoteModalOpen(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              <h3 className="text-2xl font-black text-slate-900 mb-2">Pesan Perbaikan</h3>
              <p className="text-slate-500 text-sm mb-6 leading-relaxed italic">
                Admin memberikan catatan berikut untuk pengajuan <b>"{selectedRequestForNote.trainingTitle}"</b>:
              </p>

              <div className="bg-red-50/50 border-2 border-red-100 rounded-2xl p-6 mb-8">
                <p className="text-slate-700 font-bold leading-relaxed whitespace-pre-wrap">
                  {selectedRequestForNote.organizerComment || "Tidak ada catatan spesifik."}
                </p>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => setIsNoteModalOpen(false)}
                  className="flex-1 px-6 py-4 rounded-xl text-xs font-black text-slate-400 uppercase tracking-widest hover:bg-slate-50 transition-colors"
                >
                  Tutup
                </button>
                <button 
                  onClick={handlePerbaiki}
                  className="flex-[2] bg-red-600 hover:bg-red-700 text-white px-8 py-4 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl shadow-red-100 transition-all active:scale-95"
                >
                  Perbaiki Pengajuan
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Dashboard Instruktur</h2>
          <p className="text-slate-500 text-sm">Hanya menampilkan data pengajuan milik <b>{user.displayName}</b>.</p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 shadow-lg shadow-blue-100 active:scale-95"
        >
          {showForm ? 'Tutup Form' : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
              </svg>
              Buat Pengajuan
            </>
          )}
        </button>
      </div>

      {showForm && (
        <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-200">
          <div className="p-8">
            <div className="flex items-center gap-3 mb-8 pb-4 border-b border-slate-100">
              <div className="bg-blue-100 p-2.5 rounded-xl">
                <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Form Pengajuan Bahan</h3>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-6">
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Kejuruan</label>
                    <select
                      value={vocation}
                      onChange={(e) => setVocation(e.target.value as VocationalCategory)}
                      className="w-full bg-slate-50 border-slate-200 rounded-xl py-3 px-4 text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-100 focus:border-blue-400 transition-all cursor-pointer"
                    >
                      {Object.values(VocationalCategory).map((v) => (
                        <option key={v} value={v}>{v}</option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Program Pelatihan (Proglat)</label>
                    <select
                      value={proglat}
                      onChange={(e) => setProglat(e.target.value)}
                      className="w-full bg-slate-50 border-slate-200 rounded-xl py-3 px-4 text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-100 focus:border-blue-400 transition-all cursor-pointer"
                    >
                      {(PROGLAT_MAPPING[vocation] || []).map((p) => (
                        <option key={p} value={p}>{p}</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="space-y-6">
                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Judul Pelatihan</label>
                    <input
                      type="text"
                      required
                      value={trainingTitle}
                      onChange={(e) => setTrainingTitle(e.target.value)}
                      placeholder="Masukkan nama kelas/pelatihan"
                      className="w-full bg-slate-50 border-slate-200 rounded-xl py-3 px-4 text-sm font-bold placeholder:text-slate-300 focus:ring-4 focus:ring-blue-100 focus:border-blue-400 transition-all"
                    />
                  </div>

                  <div>
                    <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Dokumen Pengajuan (Excel/PDF)</label>
                    <div
                      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
                      onDragLeave={() => setIsDragging(false)}
                      onDrop={handleDrop}
                      className={`relative border-2 border-dashed rounded-2xl p-6 text-center transition-all ${
                        isDragging ? 'border-blue-500 bg-blue-50' : 'border-slate-200 hover:border-blue-400 bg-slate-50'
                      }`}
                    >
                      <input
                        type="file"
                        accept=".xlsx,.xls,.pdf"
                        onChange={handleFileChange}
                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                      />
                      <div className="flex flex-col items-center gap-2">
                        {file ? (
                          <>
                            <div className="bg-green-100 p-2 rounded-lg mb-1">
                              <svg className="w-6 h-6 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                              </svg>
