import { GoogleGenAI, Type } from "@google/genai";

// Fix: Use the API_KEY from process.env directly per Google GenAI SDK guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const suggestMaterials = async (trainingTitle: string, vocation: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Berikan daftar saran bahan pelatihan yang dibutuhkan untuk topik: "${trainingTitle}" dalam bidang kejuruan: "${vocation}". Berikan item yang sangat relevan dengan praktik kejuruan tersebut.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING, description: "Nama barang" },
              quantity: { type: Type.NUMBER, description: "Jumlah standar" },
              unit: { type: Type.STRING, description: "Satuan (misal: Rim, Pack, Buah)" },
              spec: { type: Type.STRING, description: "Spesifikasi singkat" }
            },
            required: ["name", "quantity", "unit", "spec"]
          }
        }
      }
    });

    // Fix: response.text is a property. Added fallback to empty array string for safer parsing.
    return JSON.parse(response.text || '[]');
  } catch (error) {
    console.error("Gemini Suggestion Error:", error);
    return [];
  }
};

import React, { useState, useEffect } from 'react';
import { MaterialRequest, RequestStatus, VocationalCategory, VOCATION_COLORS, PROGLAT_MAPPING, User } from '../types';

interface InstructorViewProps {
  user: User;
  requests: MaterialRequest[];
  onSubmit: (req: Partial<MaterialRequest>) => void;
}

const InstructorView: React.FC<InstructorViewProps> = ({ user, requests, onSubmit }) => {
  const [showForm, setShowForm] = useState(false);
  const [vocation, setVocation] = useState<VocationalCategory>(user.vocation || VocationalCategory.TIK);
  const [proglat, setProglat] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Revision Modal State
  const [selectedRequestForNote, setSelectedRequestForNote] = useState<MaterialRequest | null>(null);
  const [isNoteModalOpen, setIsNoteModalOpen] = useState(false);

  // Sync proglat when vocation changes
  useEffect(() => {
    const programs = PROGLAT_MAPPING[vocation] || [];
    setProglat(programs[0] || '');
  }, [vocation]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setFile(e.dataTransfer.files[0]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) return alert("Silakan upload dokumen pengajuan (Excel/PDF) terlebih dahulu!");

    onSubmit({
      // Judul otomatis menggunakan nilai Proglat yang dipilih
      trainingTitle: proglat,
      vocation,
      proglat,
      items: [],
      attachmentName: file.name,
      instructorName: user.username,
      status: RequestStatus.PENDING,
      dateSubmitted: new Date().toISOString()
    });

    setFile(null);
    setShowForm(false);
  };

  const openNoteModal = (req: MaterialRequest) => {
    setSelectedRequestForNote(req);
    setIsNoteModalOpen(true);
  };

  const handlePerbaiki = () => {
    if (selectedRequestForNote) {
      setVocation(selectedRequestForNote.vocation);
      setProglat(selectedRequestForNote.proglat);
      setShowForm(true);
      setIsNoteModalOpen(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Note Modal for Revision */}
      {isNoteModalOpen && selectedRequestForNote && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8">
              <div className="flex justify-between items-start mb-6">
                <div className="bg-red-100 p-3 rounded-2xl">
                  <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                  </svg>
                </div>
                <button onClick={() => setIsNoteModalOpen(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              <h3 className="text-2xl font-black text-slate-900 mb-2">Pesan Perbaikan</h3>
              <p className="text-slate-500 text-sm mb-6 leading-relaxed italic">
                Admin memberikan catatan berikut untuk pengajuan <b>"{selectedRequestForNote.trainingTitle}"</b>:
              </p>

              <div className="bg-red-50/50 border-2 border-red-100 rounded-2xl p-6 mb-8">
                <p className="text-slate-700 font-bold leading-relaxed whitespace-pre-wrap">
                  {selectedRequestForNote.organizerComment || "Tidak ada catatan spesifik."}
                </p>
