            <div className="flex items-center gap-3 mb-8 pb-4 border-b border-slate-100">
              <div className="bg-blue-100 p-2.5 rounded-xl">
                <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight">Form Pengajuan Bahan</h3>
            </div>

            <form onSubmit={handleSubmit} className="max-w-2xl mx-auto space-y-8">
              <div className="grid grid-cols-1 gap-6">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Kejuruan</label>
                  <select
                    value={vocation}
                    onChange={(e) => setVocation(e.target.value as VocationalCategory)}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl py-4 px-5 text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-100 focus:border-blue-400 transition-all cursor-pointer"
                  >
                    {Object.values(VocationalCategory).map((v) => (
                      <option key={v} value={v}>{v}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Program Pelatihan (Proglat)</label>
                  <select
                    value={proglat}
                    onChange={(e) => setProglat(e.target.value)}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-xl py-4 px-5 text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-100 focus:border-blue-400 transition-all cursor-pointer"
                  >
                    {(PROGLAT_MAPPING[vocation] || []).map((p) => (
                      <option key={p} value={p}>{p}</option>
                    ))}
                  </select>
                  <p className="mt-2 text-[10px] text-slate-400 font-bold uppercase tracking-wider px-1">
                    *Nama Proglat akan digunakan sebagai Judul Pengajuan
                  </p>
                </div>

                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Dokumen Pengajuan (Excel/PDF)</label>
                  <div
                    onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
                    onDragLeave={() => setIsDragging(false)}
                    onDrop={handleDrop}
                    className={`relative border-2 border-dashed rounded-2xl p-8 text-center transition-all ${
                      isDragging ? 'border-blue-500 bg-blue-50' : 'border-slate-200 hover:border-blue-400 bg-slate-50'
                    }`}
                  >
                    <input
                      type="file"
                      accept=".xlsx,.xls,.pdf"
                      onChange={handleFileChange}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="flex flex-col items-center gap-3">
                      {file ? (
                        <>
                          <div className="bg-green-100 p-3 rounded-xl mb-1 shadow-sm">
                            <svg className="w-8 h-8 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                            </svg>
                          </div>
                          <span className="text-sm font-black text-slate-800 truncate max-w-full px-4">{file.name}</span>
                          <span className="text-[10px] text-slate-400 uppercase font-black">Klik untuk mengganti file</span>
                        </>
                      ) : (
                        <>
                          <div className="bg-blue-100 p-3 rounded-xl mb-1 shadow-sm">
                            <svg className="w-8 h-8 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                            </svg>
                          </div>
                          <span className="text-sm font-bold text-slate-600">Drag & Drop file atau klik untuk upload</span>
                          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Dukungan format: .xlsx, .xls, .pdf</span>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              <div className="pt-6 border-t border-slate-100 flex justify-end items-center gap-6">
                <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest hidden sm:block">
                  Periksa kembali data Anda sebelum mengirim
                </span>
                <button
                  type="submit"
                  className="bg-blue-600 text-white px-12 py-4 rounded-xl font-black uppercase tracking-widest hover:bg-blue-700 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  Kirim Pengajuan
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-100">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-6 py-5 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Kelas & Program</th>
                <th className="px-6 py-5 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Lampiran</th>
                <th className="px-6 py-5 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Tanggal</th>
                <th className="px-6 py-5 text-left text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
                <th className="px-6 py-5 text-right text-[10px] font-black text-slate-400 uppercase tracking-widest">Aksi</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-100">
              {requests.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-16 text-center">
                    <div className="text-slate-300 italic flex flex-col items-center gap-2">
                      <svg className="w-12 h-12 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M9 13h6m-3-3v6m-9 1V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z"/></svg>
                      Belum ada pengajuan terdaftar.
                    </div>
                  </td>
                </tr>
              ) : requests.map((req) => (
                <tr key={req.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-5">
                    <div className="text-sm font-black text-slate-800 mb-1.5">{req.trainingTitle}</div>
                    <div className="flex flex-col gap-1">
                      <div className="flex items-center gap-2">
                        <span className={`text-[9px] px-2 py-0.5 rounded-full font-black uppercase border shadow-sm ${VOCATION_COLORS[req.vocation] || 'bg-slate-100'}`}>
                          {req.vocation}
                        </span>
                      </div>
                      <span className="text-[11px] font-bold text-slate-500">{req.proglat}</span>
                    </div>
                  </td>
                  <td className="px-6 py-5">
                    {req.attachmentName ? (
                       <div className="flex items-center gap-2 text-[11px] font-bold text-blue-600 bg-blue-50 px-2.5 py-1.5 rounded-lg w-fit border border-blue-100">
                         <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                         {req.attachmentName}
                       </div>
                    ) : (
                      <span className="text-[10px] text-slate-300 italic font-medium">No File</span>
                    )}
                  </td>
                  <td className="px-6 py-5 whitespace-nowrap">
                    <div className="text-xs font-bold text-slate-600">{new Date(req.dateSubmitted).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}</div>
                    <div className="text-[9px] text-slate-400 font-medium uppercase">{new Date(req.dateSubmitted).getFullYear()}</div>
                  </td>
                  <td className="px-6 py-5">
                    <span className={`px-2.5 py-1 text-[9px] font-black rounded-full uppercase tracking-wider border shadow-sm ${
                      req.status === RequestStatus.APPROVED ? 'bg-green-50 text-green-700 border-green-200' :
                      req.status === RequestStatus.PENDING ? 'bg-amber-50 text-amber-700 border-amber-200' :
                      req.status === RequestStatus.REVISION ? 'bg-red-50 text-red-700 border-red-200' :
                      req.status === RequestStatus.FORWARDED ? 'bg-purple-900 text-white border-purple-900' :
                      'bg-slate-50 text-slate-700 border-slate-200'
                    }`}>
                      {req.status}
                    </span>
                  </td>
                  <td className="px-6 py-5 text-right">
                    {req.status === RequestStatus.REVISION ? (
                      <button 
                        onClick={() => openNoteModal(req)}
                        className="text-[11px] font-black uppercase text-red-600 hover:text-white bg-red-50 hover:bg-red-600 px-4 py-2 rounded-xl transition-all tracking-widest border border-red-100"
                      >
                        Lihat Catatan
                      </button>
                    ) : (
                      <button className="text-[11px] font-black uppercase text-blue-600 hover:text-white bg-blue-50 hover:bg-blue-600 px-4 py-2 rounded-xl transition-all tracking-widest border border-blue-100">
                        Detail
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default InstructorView;

