              alt="Logo Kemnaker" 
              className="h-20 w-auto object-contain"
            />
          </div>
          <h1 className="text-4xl font-black text-[#003399] tracking-tighter uppercase">SI PELA</h1>
          <p className="text-slate-500 font-bold text-sm mt-2 uppercase tracking-widest">Sistem Pengajuan Bahan Pelatihan</p>
