import React, { useState, useEffect } from 'react';
import { MaterialRequest, UserRole, RequestStatus, VocationalCategory, PROGLAT_MAPPING, User, KEMNAKER_LOGO_BASE64 } from './types';
import DashboardHeader from './components/DashboardHeader';
import InstructorView from './components/InstructorView';
import OrganizerView from './components/OrganizerView';
import Login from './components/Login';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);

  // Auth persistence check
  useEffect(() => {
    const savedUser = localStorage.getItem('simpro_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  // Load mock data on mount
  useEffect(() => {
    const saved = localStorage.getItem('simpro_requests');
    if (saved) {
      setRequests(JSON.parse(saved));
    } else {
      const mock: MaterialRequest[] = [
        {
          id: 'tik-1',
          instructorName: 'richad',
          trainingTitle: PROGLAT_MAPPING[VocationalCategory.TIK][0],
          vocation: VocationalCategory.TIK,
          proglat: PROGLAT_MAPPING[VocationalCategory.TIK][0],
          dateSubmitted: new Date(Date.now() - 1800000).toISOString(),
          items: [],
          attachmentName: 'daftar_bahan_web.xlsx',
          status: RequestStatus.PENDING
        },
        {
          id: 'las-1',
          instructorName: 'papang',
          trainingTitle: 'Plate Welder SMAW 3G',
          vocation: VocationalCategory.LAS,
          proglat: 'Plate Welder SMAW 3G',
          dateSubmitted: new Date(Date.now() - 5400000).toISOString(),
          items: [],
          attachmentName: 'kebutuhan_elektroda.pdf',
          status: RequestStatus.PENDING
        },
        {
          id: 'oto-1',
          instructorName: 'papang',
          trainingTitle: 'Servis Sepeda Motor Injeksi',
          vocation: VocationalCategory.OTOMOTIF,
          proglat: 'Servis Sepeda Motor Injeksi',
          dateSubmitted: new Date(Date.now() - 86400000).toISOString(),
          items: [],
          attachmentName: 'sparepart_praktik.xlsx',
          status: RequestStatus.APPROVED
        },
        {
          id: 'bag-1',
          instructorName: 'richad',
          trainingTitle: 'Drafter CAD',
          vocation: VocationalCategory.BANGUNAN,
          proglat: 'Drafter CAD',
          dateSubmitted: new Date(Date.now() - 172800000).toISOString(),
          items: [],
          attachmentName: 'peralatan_gambar.pdf',
          status: RequestStatus.REVISION,
          organizerComment: "Spesifikasi software mohon diperjelas."
        }
      ];
      setRequests(mock);
      localStorage.setItem('simpro_requests', JSON.stringify(mock));
    }
  }, []);

  const saveRequests = (newReqs: MaterialRequest[]) => {
    setRequests(newReqs);
    localStorage.setItem('simpro_requests', JSON.stringify(newReqs));
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('simpro_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('simpro_user');
  };

  const handleInstructorSubmit = (req: Partial<MaterialRequest>) => {
    const newReq: MaterialRequest = {
      ...req,
      id: Math.random().toString(36).substr(2, 9),
    } as MaterialRequest;
    saveRequests([newReq, ...requests]);
  };

  const handleOrganizerAction = (id: string, status: RequestStatus, comment?: string, signedDoc?: string) => {
    const updated = requests.map(r => 
      r.id === id ? { 
        ...r, 
        status, 
        organizerComment: comment || r.organizerComment,
        signedDocumentName: signedDoc || r.signedDocumentName 
      } : r
    );
    saveRequests(updated);
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-100 selection:bg-blue-100 selection:text-[#003399]">
      <DashboardHeader user={currentUser} onLogout={handleLogout} />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="max-w-5xl mx-auto">
          {currentUser.role === UserRole.INSTRUCTOR ? (
            <InstructorView 
              user={currentUser}
              requests={requests.filter(r => r.instructorName === currentUser.username)}
              onSubmit={handleInstructorSubmit}
            />
          ) : (
            <OrganizerView 
              requests={requests}
              onAction={handleOrganizerAction}
            />
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-12 mt-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
           <div className="flex flex-col md:flex-row justify-between items-center gap-10">
              <div className="flex items-center gap-6">
                 <img 
                    src={KEMNAKER_LOGO_BASE64} 
                    alt="Logo Kemnaker" 
                    className="h-16 w-auto grayscale opacity-50 hover:grayscale-0 hover:opacity-100 transition-all"
                 />
                 <div className="h-12 w-px bg-slate-200"></div>
                 <div>
                    <h1 className="text-xl font-black text-slate-800 tracking-tighter uppercase">SI PELA</h1>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Kementerian Ketenagakerjaan RI</p>
                 </div>
              </div>

              <div className="flex flex-col items-center md:items-end gap-3">
                 <div className="flex gap-10 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
                    <span className="hover:text-[#003399] cursor-pointer transition-colors">Bantuan</span>
                    <span className="hover:text-[#003399] cursor-pointer transition-colors">Panduan Sistem</span>
                    <span className="hover:text-[#003399] cursor-pointer transition-colors">Kebijakan Privasi</span>
                 </div>
                 <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">© 2024 SI PELA - Direktorat Jenderal Binalavotas</p>
              </div>
           </div>
        </div>
      </footer>
    </div>
  );
};

