import React, { useState, useEffect } from 'react';
import { MaterialRequest, RequestStatus, VocationalCategory, VOCATION_COLORS, PROGLAT_MAPPING, User } from '../types';

interface InstructorViewProps {
  user: User;
  requests: MaterialRequest[];
  onSubmit: (req: Partial<MaterialRequest>) => void;
}

const InstructorView: React.FC<InstructorViewProps> = ({ user, requests, onSubmit }) => {
  const [showForm, setShowForm] = useState(false);
  const [vocation, setVocation] = useState<VocationalCategory>(user.vocation || VocationalCategory.TIK);
  const [proglat, setProglat] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [isDragging, setIsDragging] = useState(false);

  // Revision Modal State
  const [selectedRequestForNote, setSelectedRequestForNote] = useState<MaterialRequest | null>(null);
  const [isNoteModalOpen, setIsNoteModalOpen] = useState(false);

  // Sync proglat when vocation changes
  useEffect(() => {
    const programs = PROGLAT_MAPPING[vocation] || [];
    setProglat(programs[0] || '');
  }, [vocation]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      setFile(e.dataTransfer.files[0]);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!file) return alert("Silakan upload dokumen pengajuan (Excel/PDF) terlebih dahulu!");

    onSubmit({
      trainingTitle: proglat,
      vocation,
      proglat,
      items: [],
      attachmentName: file.name,
      instructorName: user.username,
      status: RequestStatus.PENDING,
      dateSubmitted: new Date().toISOString()
    });

    setFile(null);
    setShowForm(false);
  };

  const openNoteModal = (req: MaterialRequest) => {
    setSelectedRequestForNote(req);
    setIsNoteModalOpen(true);
  };

  const handlePerbaiki = () => {
    if (selectedRequestForNote) {
      setVocation(selectedRequestForNote.vocation);
      setProglat(selectedRequestForNote.proglat);
      setShowForm(true);
      setIsNoteModalOpen(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Note Modal for Revision */}
      {isNoteModalOpen && selectedRequestForNote && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8">
              <div className="flex justify-between items-start mb-6">
                <div className="bg-red-100 p-3 rounded-2xl">
                  <svg className="w-8 h-8 text-red-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                  </svg>
                </div>
                <button onClick={() => setIsNoteModalOpen(false)} className="text-slate-400 hover:text-slate-600 transition-colors">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
                </button>
              </div>

              <h3 className="text-2xl font-black text-slate-900 mb-2">Pesan Perbaikan</h3>
              <p className="text-slate-500 text-sm mb-6 leading-relaxed italic">
                Admin memberikan catatan berikut untuk pengajuan <b>"{selectedRequestForNote.trainingTitle}"</b>:
              </p>

              <div className="bg-red-50/50 border-2 border-red-100 rounded-2xl p-6 mb-8">
                <p className="text-slate-700 font-bold leading-relaxed whitespace-pre-wrap">
                  {selectedRequestForNote.organizerComment || "Tidak ada catatan spesifik."}
                </p>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => setIsNoteModalOpen(false)}
                  className="flex-1 px-6 py-4 rounded-xl text-xs font-black text-slate-400 uppercase tracking-widest hover:bg-slate-50 transition-colors"
                >
                  Tutup
                </button>
                <button 
                  onClick={handlePerbaiki}
                  className="flex-[2] bg-red-600 hover:bg-red-700 text-white px-8 py-4 rounded-xl text-xs font-black uppercase tracking-widest shadow-xl shadow-red-100 transition-all active:scale-95"
                >
                  Perbaiki Pengajuan
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Dashboard Instruktur</h2>
          <p className="text-slate-500 text-sm">Hanya menampilkan data pengajuan milik <b>{user.displayName}</b>.</p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="bg-[#003399] hover:bg-[#0d47a1] text-white px-6 py-3 rounded-xl font-black uppercase text-xs tracking-widest transition-all flex items-center gap-2 shadow-lg shadow-blue-100 active:scale-95"
        >
          {showForm ? 'Tutup Form' : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 4v16m8-8H4" />
              </svg>
              Buat Pengajuan
            </>
          )}
        </button>
      </div>

      {showForm && (
        <div className="bg-white rounded-3xl shadow-xl border border-slate-200 overflow-hidden animate-in zoom-in-95 duration-200">
          <div className="p-8">
            <div className="flex items-center gap-3 mb-8 pb-4 border-b border-slate-100">
              <div className="bg-blue-50 p-3 rounded-2xl">
                <svg className="w-6 h-6 text-[#003399]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <h3 className="text-xl font-black text-slate-800 tracking-tight uppercase">Form Pengajuan Bahan</h3>
            </div>

            <form onSubmit={handleSubmit} className="max-w-2xl mx-auto space-y-8">
              <div className="grid grid-cols-1 gap-6">
                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Kejuruan</label>
                  <select
                    value={vocation}
                    onChange={(e) => setVocation(e.target.value as VocationalCategory)}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-4 px-6 text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-100 focus:border-[#003399] transition-all cursor-pointer appearance-none"
                  >
                    {Object.values(VocationalCategory).map((v) => (
                      <option key={v} value={v}>{v}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Program Pelatihan (Proglat)</label>
                  <select
                    value={proglat}
                    onChange={(e) => setProglat(e.target.value)}
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-4 px-6 text-sm font-bold text-slate-700 focus:ring-4 focus:ring-blue-100 focus:border-[#003399] transition-all cursor-pointer appearance-none"
                  >
                    {(PROGLAT_MAPPING[vocation] || []).map((p) => (
                      <option key={p} value={p}>{p}</option>
                    ))}
                  </select>
                  <p className="mt-2 text-[10px] text-slate-400 font-bold uppercase tracking-wider px-1 italic">
                    *Nama Proglat akan digunakan sebagai Judul Pengajuan Otomatis
                  </p>
                </div>

                <div>
                  <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Dokumen Lampiran (Excel/PDF)</label>
                  <div
                    onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
                    onDragLeave={() => setIsDragging(false)}
                    onDrop={handleDrop}
                    className={`relative border-2 border-dashed rounded-3xl p-10 text-center transition-all ${
                      isDragging ? 'border-[#003399] bg-blue-50' : 'border-slate-200 hover:border-[#003399] bg-slate-50'
                    }`}
                  >
                    <input
                      type="file"
                      accept=".xlsx,.xls,.pdf"
                      onChange={handleFileChange}
                      className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                    />
                    <div className="flex flex-col items-center gap-4">
                      {file ? (
                        <>
                          <div className="bg-green-100 p-4 rounded-2xl mb-1 shadow-sm">
                            <svg className="w-10 h-10 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
                            </svg>
                          </div>
                          <span className="text-sm font-black text-slate-800 truncate max-w-full px-4">{file.name}</span>
                          <span className="text-[10px] text-slate-400 uppercase font-black tracking-widest">Klik untuk mengganti berkas</span>
                        </>
                      ) : (
                        <>
                          <div className="bg-blue-100 p-4 rounded-2xl mb-1 shadow-sm">
                            <svg className="w-10 h-10 text-[#003399]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                            </svg>
                          </div>
                          <span className="text-sm font-bold text-slate-600">Seret file ke sini atau klik untuk memilih</span>
                          <span className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">Hanya mendukung: Excel & PDF</span>
                        </>
                      )}
                    </div>
                  </div>
                </div>
              </div>

              <div className="pt-8 border-t border-slate-100 flex justify-end items-center gap-6">
                <span className="text-[10px] text-slate-400 font-black uppercase tracking-widest hidden sm:block">
                  Pastikan data yang diunggah valid
                </span>
                <button
                  type="submit"
                  className="bg-[#003399] text-white px-14 py-5 rounded-2xl font-black uppercase tracking-[0.25em] text-xs hover:bg-[#0d47a1] shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  Kirim Pengajuan
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-100">
            <thead className="bg-slate-50/50">
              <tr>
                <th className="px-6 py-6 text-left text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Kelas & Program</th>
                <th className="px-6 py-6 text-left text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Lampiran</th>
                <th className="px-6 py-6 text-left text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Tanggal</th>
                <th className="px-6 py-6 text-left text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Status</th>
                <th className="px-6 py-6 text-right text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Aksi</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-slate-100">
              {requests.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-20 text-center">
                    <div className="text-slate-300 italic flex flex-col items-center gap-3">
                      <svg className="w-14 h-14 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1" d="M9 13h6m-3-3v6m-9 1V7a2 2 0 012-2h6l2 2h6a2 2 0 012 2v8a2 2 0 01-2 2H5a2 2 0 01-2-2z"/></svg>
                      <span className="font-bold uppercase tracking-widest text-xs">Belum ada pengajuan terdaftar</span>
                    </div>
                  </td>
                </tr>
              ) : requests.map((req) => (
                <tr key={req.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="px-6 py-6">
                    <div className="text-sm font-black text-slate-800 mb-2">{req.trainingTitle}</div>
                    <div className="flex flex-col gap-1.5">
                      <div className="flex items-center gap-2">
                        <span className={`text-[9px] px-3 py-0.5 rounded-full font-black uppercase border shadow-sm ${VOCATION_COLORS[req.vocation] || 'bg-slate-100'}`}>
                          {req.vocation}
                        </span>
                      </div>
                      <span className="text-[11px] font-bold text-slate-500">{req.proglat}</span>
                    </div>
                  </td>
                  <td className="px-6 py-6">
                    {req.attachmentName ? (
                       <div className="flex items-center gap-2 text-[11px] font-black text-[#003399] bg-blue-50 px-3 py-2 rounded-xl w-fit border border-blue-100">
                         <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"/></svg>
                         {req.attachmentName}
                       </div>
                    ) : (
                      <span className="text-[10px] text-slate-300 italic font-medium uppercase">No File</span>
                    )}
                  </td>
                  <td className="px-6 py-6 whitespace-nowrap">
                    <div className="text-xs font-black text-slate-700">{new Date(req.dateSubmitted).toLocaleDateString('id-ID', { day: 'numeric', month: 'short' })}</div>
                    <div className="text-[9px] text-slate-400 font-bold uppercase tracking-wider">{new Date(req.dateSubmitted).getFullYear()}</div>
                  </td>
                  <td className="px-6 py-6">
                    <span className={`inline-block px-3 py-1 text-[9px] font-black rounded-xl uppercase tracking-widest border shadow-sm whitespace-nowrap min-w-fit text-center ${
                      req.status === RequestStatus.APPROVED ? 'bg-green-50 text-green-700 border-green-200' :
                      req.status === RequestStatus.PENDING ? 'bg-amber-50 text-amber-700 border-amber-200' :
                      req.status === RequestStatus.REVISION ? 'bg-red-50 text-red-700 border-red-200' :
                      req.status === RequestStatus.FORWARDED ? 'bg-purple-100 text-purple-800 border-purple-200' :
                      'bg-slate-50 text-slate-700 border-slate-200'
                    }`}>
                      {req.status}
                    </span>
                  </td>
                  <td className="px-6 py-6 text-right">
                    {req.status === RequestStatus.REVISION ? (
                      <button 
                        onClick={() => openNoteModal(req)}
                        className="text-[10px] font-black uppercase text-red-600 hover:text-white bg-red-50 hover:bg-red-600 px-5 py-2.5 rounded-xl transition-all tracking-[0.15em] border border-red-100"
                      >
                        Lihat Catatan
                      </button>
                    ) : (
                      <button className="text-[10px] font-black uppercase text-[#003399] hover:text-white bg-blue-50 hover:bg-[#003399] px-5 py-2.5 rounded-xl transition-all tracking-[0.15em] border border-blue-100">
                        Detail
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default InstructorView;

import React, { useState, useEffect } from 'react';
import { MaterialRequest, UserRole, RequestStatus, VocationalCategory, PROGLAT_MAPPING, User } from './types';
import DashboardHeader from './components/DashboardHeader';
import InstructorView from './components/InstructorView';
import OrganizerView from './components/OrganizerView';
import ProfileView from './components/ProfileView';
import Login from './components/Login';
import KemnakerLogo from './components/KemnakerLogo';

type TabType = 'home' | 'profile';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [requests, setRequests] = useState<MaterialRequest[]>([]);
  const [activeTab, setActiveTab] = useState<TabType>('home');

  // Auth persistence check
  useEffect(() => {
    const savedUser = localStorage.getItem('simpro_user');
    if (savedUser) {
      setCurrentUser(JSON.parse(savedUser));
    }
  }, []);

  // Load mock data on mount
  useEffect(() => {
    const saved = localStorage.getItem('simpro_requests');
    if (saved) {
      setRequests(JSON.parse(saved));
    } else {
      const mock: MaterialRequest[] = [
        {
          id: 'tik-1',
          instructorName: 'richad',
          trainingTitle: PROGLAT_MAPPING[VocationalCategory.TIK][0],
          vocation: VocationalCategory.TIK,
          proglat: PROGLAT_MAPPING[VocationalCategory.TIK][0],
          dateSubmitted: new Date(Date.now() - 1800000).toISOString(),
          items: [],
          attachmentName: 'daftar_bahan_web.xlsx',
          status: RequestStatus.PENDING
        },
        {
          id: 'las-1',
          instructorName: 'papang',
          trainingTitle: 'Plate Welder SMAW 3G',
          vocation: VocationalCategory.LAS,
          proglat: 'Plate Welder SMAW 3G',
          dateSubmitted: new Date(Date.now() - 5400000).toISOString(),
          items: [],
          attachmentName: 'kebutuhan_elektroda.pdf',
          status: RequestStatus.PENDING
        },
        {
          id: 'oto-1',
          instructorName: 'instruktur_oto',
          trainingTitle: 'Servis Sepeda Motor Injeksi',
          vocation: VocationalCategory.OTOMOTIF,
          proglat: 'Servis Sepeda Motor Injeksi',
          dateSubmitted: new Date(Date.now() - 86400000).toISOString(),
          items: [],
          attachmentName: 'sparepart_praktik.xlsx',
          status: RequestStatus.APPROVED
        },
        {
          id: 'bag-1',
          instructorName: 'richad',
          trainingTitle: 'Drafter CAD',
          vocation: VocationalCategory.BANGUNAN,
          proglat: 'Drafter CAD',
          dateSubmitted: new Date(Date.now() - 172800000).toISOString(),
          items: [],
          attachmentName: 'peralatan_gambar.pdf',
          status: RequestStatus.REVISION,
          organizerComment: "Spesifikasi software mohon diperjelas."
        }
      ];
      setRequests(mock);
      localStorage.setItem('simpro_requests', JSON.stringify(mock));
    }
  }, []);

  const saveRequests = (newReqs: MaterialRequest[]) => {
    setRequests(newReqs);
    localStorage.setItem('simpro_requests', JSON.stringify(newReqs));
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('simpro_user', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('simpro_user');
    setActiveTab('home');
  };

  const handleInstructorSubmit = (req: Partial<MaterialRequest>) => {
    const newReq: MaterialRequest = {
      ...req,
      id: Math.random().toString(36).substr(2, 9),
    } as MaterialRequest;
    saveRequests([newReq, ...requests]);
  };

  const handleOrganizerAction = (id: string, status: RequestStatus, comment?: string, signedDoc?: string) => {
    const updated = requests.map(r => 
      r.id === id ? { 
        ...r, 
        status, 
        organizerComment: comment || r.organizerComment,
        signedDocumentName: signedDoc || r.signedDocumentName 
      } : r
    );
    saveRequests(updated);
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  const getPersonalData = () => {
    if (currentUser.role === UserRole.ADMIN) return requests;
    return requests.filter(r => 
      r.instructorName === currentUser.username && 
      r.vocation === currentUser.vocation
    );
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-100 selection:bg-blue-100 selection:text-[#003399]">
      {/* Header - Hidden on mobile */}
      <div className="hidden md:block">
        <DashboardHeader user={currentUser} onLogout={handleLogout} />
      </div>

      {/* Mobile Top Branding - Only visible on small screens when on profile */}
      <div className="md:hidden bg-[#003399] p-4 flex justify-center items-center gap-3">
          <KemnakerLogo className="h-6 w-6 text-white" />
          <h1 className="text-white font-black uppercase text-sm tracking-widest">SI PELA</h1>
      </div>

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-6 md:py-10">
        <div className="max-w-5xl mx-auto">
          {activeTab === 'home' ? (
            currentUser.role === UserRole.INSTRUCTOR ? (
              <InstructorView 
                user={currentUser}
                requests={getPersonalData()}
                onSubmit={handleInstructorSubmit}
              />
            ) : (
              <OrganizerView 
                requests={requests}
                onAction={handleOrganizerAction}
              />
            )
          ) : (
            <ProfileView 
              user={currentUser}
              onLogout={handleLogout}
            />
          )}
        </div>
      </main>

      {/* Desktop Footer - Hidden on mobile */}
      <footer className="hidden md:block bg-white border-t border-slate-200 py-12 mt-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
           <div className="flex flex-col md:flex-row justify-between items-center gap-10">
              <div className="flex items-center gap-6">
                 <div className="bg-slate-50 p-2 rounded-xl grayscale opacity-50 hover:grayscale-0 hover:opacity-100 transition-all">
                    <KemnakerLogo className="h-12 w-12 text-[#003399]" />
                 </div>
                 <div className="h-12 w-px bg-slate-200"></div>
                 <div>
                    <h1 className="text-xl font-black text-slate-800 tracking-tighter uppercase">SI PELA</h1>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mt-1">Kementerian Ketenagakerjaan RI</p>
                 </div>
              </div>

              <div className="flex flex-col items-center md:items-end gap-3">
                 <div className="flex gap-10 text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
                    <span className="hover:text-[#003399] cursor-pointer transition-colors">Bantuan</span>
                    <span className="hover:text-[#003399] cursor-pointer transition-colors">Panduan Sistem</span>
                    <span className="hover:text-[#003399] cursor-pointer transition-colors">Kebijakan Privasi</span>
                 </div>
                 <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">© 2024 SI PELA - Direktorat Jenderal Binalavotas</p>
              </div>
           </div>
        </div>
      </footer>

      {/* Mobile Bottom Navigation - Only visible on small screens */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 flex items-center justify-around h-20 px-6 z-50 shadow-[0_-10px_30px_-15px_rgba(0,0,0,0.1)]">
        <button 
          onClick={() => setActiveTab('home')}
          className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'home' ? 'text-[#003399]' : 'text-slate-400'}`}
        >
          <div className={`p-2 rounded-2xl transition-all ${activeTab === 'home' ? 'bg-blue-50' : 'bg-transparent'}`}>
            <svg className="w-6 h-6" fill={activeTab === 'home' ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
            </svg>
          </div>
          <span className="text-[9px] font-black uppercase tracking-widest">Beranda</span>
        </button>

        <button 
          onClick={() => setActiveTab('profile')}
          className={`flex flex-col items-center gap-1 transition-all ${activeTab === 'profile' ? 'text-[#003399]' : 'text-slate-400'}`}
        >
          <div className={`p-2 rounded-2xl transition-all ${activeTab === 'profile' ? 'bg-blue-50' : 'bg-transparent'}`}>
            <svg className="w-6 h-6" fill={activeTab === 'profile' ? "currentColor" : "none"} stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
            </svg>
          </div>
          <span className="text-[9px] font-black uppercase tracking-widest">Akun Saya</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { MOCK_USERS, User } from '../types';
import KemnakerLogo from './KemnakerLogo';

interface LoginProps {
  onLogin: (user: User) => void;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');

    // Simulasi delay loading agar terasa seperti sistem sedang memproses
    setTimeout(() => {
      const user = MOCK_USERS.find(u => u.username === username && u.password === password);
      if (user) {
        onLogin(user);
      } else {
        setError('Login Gagal: Username atau password salah');
        setIsLoading(false);
      }
    }, 800);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-100 px-4">
      <div className="max-w-md w-full">
        <div className="text-center mb-8">
          <div className="bg-white p-6 rounded-[2rem] shadow-xl inline-block mb-6 border border-slate-200">
            <KemnakerLogo className="w-16 h-16 text-[#003399]" />
          </div>
          <h1 className="text-4xl font-black text-[#003399] tracking-tighter uppercase">SI PELA</h1>
          <p className="text-slate-500 font-bold text-sm mt-2 uppercase tracking-widest">Sistem Pengajuan Bahan Pelatihan</p>
        </div>

        <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl border border-slate-100 relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-2 bg-[#003399]"></div>

          <form onSubmit={handleSubmit} className="space-y-6">
            {error && (
              <div className="bg-red-50 text-red-600 text-[10px] font-black uppercase tracking-widest p-4 rounded-2xl border border-red-100 flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
                <svg className="w-5 h-5 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
                {error}
              </div>
            )}

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Username</label>
              <input
                type="text"
                required
                disabled={isLoading}
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-4 px-6 text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-[#003399] focus:border-[#003399] transition-all placeholder:text-slate-300 disabled:opacity-50"
                placeholder="Masukkan username"
              />
            </div>

            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Password</label>
              <div className="relative">
                <input
                  type={showPassword ? "text" : "password"}
                  required
                  disabled={isLoading}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl py-4 px-6 text-sm font-bold text-slate-700 outline-none focus:ring-2 focus:ring-[#003399] focus:border-[#003399] transition-all placeholder:text-slate-300 disabled:opacity-50"
                  placeholder="••••••••"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600 transition-colors p-1"
                >
                  {showPassword ? (
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.542-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" />
                    </svg>
                  ) : (
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                    </svg>
                  )}
                </button>
              </div>
            </div>

            <button
              type="submit"
              disabled={isLoading}
              className="w-full bg-[#003399] hover:bg-[#0d47a1] text-white font-black py-5 rounded-2xl text-xs uppercase tracking-[0.25em] transition-all shadow-xl shadow-blue-200 active:scale-95 flex items-center justify-center gap-3 disabled:opacity-70 disabled:cursor-not-allowed"
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  MEMPROSES...
                </>
              ) : (
                "MASUK"
              )}
            </button>
          </form>

          <div className="mt-10 pt-8 border-t border-slate-50 flex flex-col items-center gap-4">
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-[0.25em] opacity-80">© 2026 BPVP Ambon - Kemnaker RI</p>
            <div className="flex gap-4">
              <span className="text-[9px] bg-slate-100 text-slate-500 px-4 py-1.5 rounded-full font-black uppercase tracking-tighter cursor-default hover:bg-slate-200 transition-colors">admin / admin123</span>
              <span className="text-[9px] bg-slate-100 text-slate-500 px-4 py-1.5 rounded-full font-black uppercase tracking-tighter cursor-default hover:bg-slate-200 transition-colors">papang / 123</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
